function LxSpineDp:Dispose()
    local objectClicker = self:GetObjectClicker()
    if objectClicker then
        objectClicker.onClick = nil
        objectClicker.onClickBegin = nil
        objectClicker.onClickEnd = nil
        objectClicker.onBeginDrag = nil
        objectClicker.onDrag = nil
        objectClicker.onEndDrag = nil
    end
    self:UnRegisterAnimationComplete()

    local parts = self._skinParts
    if parts then
        for k,v in pairs(parts) do
            parts[k] = nil
            v:Dispose()
        end
    end

    LxBaseDp.Dispose(self)
end

function LxSpineDp:InitDp(dpName,parent,spineType)
    spineType = spineType or LxSpineDp.TYPE_MODEL
    self._modelName = dpName
    local assetsName = dpName
    if spineType == LxSpineDp.TYPE_UI then
        assetsName = assetsName .. "UI"
    end
    self._assetPath = "Spine/"..dpName.."/"..assetsName..".prefab"
    self._parentTrans = parent
    self._spineType = spineType
end

function LxSpineDp:InitUIDp(dpName,parent)
