function LxSpineDp:OnLoaded()
    self:InternalInitSpine()
    self:InitObjectClicker()

    if self:IsRecycled() then --在回收池子中，为了减少更新， 禁用组件
        self:EnableSkeleton(false)
    end
end

function LxSpineDp:InternalInitSpine()
    local dpGo = self._dpGo
    local skeletonAnimation = dpGo:GetComponent(typeOfSkeletonAnimation)
    if self._spineType == LxSpineDp.TYPE_UI then
        skeletonAnimation = dpGo:GetComponent(typeOfSkeletonGraphic)
        if skeletonAnimation and not skeletonAnimation.IsValid then
            skeletonAnimation:Initialize(true)
        end
    else
        self._renderer = dpGo:GetComponent(typeOfMeshRenderer)
    end

    local skeleton = skeletonAnimation.Skeleton
    local animationState = skeletonAnimation.AnimationState

    if not skeleton or not animationState then return end

    local skeletonData = skeleton.Data
    self._animationState = animationState
    self._skeletonAnimation = skeletonAnimation
    self._skeleton = skeleton
    self._skeletonData = skeletonData

    local dirtyRecordMap = self._dirtyRecordMap
    for dirtyName, isDirty in pairs(dirtyRecordMap) do
        if isDirty then
            dirtyRecordMap[dirtyName] = false
            local func = _DirtyUpdateMethods[dirtyName]
            if func ~= nil then
                func(self)
            end
        end
    end

    --为了马上刷新上面的各种设置 调用一次update 强制更新
    skeletonAnimation:Update(0)

    self:RegisterAnimationComplete()

    self:ResumeAnimation()
end

function LxSpineDp:InitObjectClicker()
    local dpGo = self:GetDpGo()
    local objectClicker = dpGo:GetComponent(typeCObjectClicker)
    if not objectClicker then
        objectClicker = dpGo:AddComponent(typeCObjectClicker)
    end
    objectClicker.enabled = true
    self._objectClicker = objectClicker
end

function LxSpineDp:GetObjectClicker()
    return self._objectClicker
end

function LxSpineDp:InnerInitRoleSkin()
    local dpGo = self:GetDpGo()
    local roleSkin = dpGo:GetComponent(typeCRoleSkin)
    if not roleSkin then
        roleSkin = dpGo:AddComponent(typeCRoleSkin)
        roleSkin:Initialize()
    end
    self._skeleton = self._skeletonAnimation.Skeleton
    self._skeletonData = self._skeleton.Data

    roleSkin.enabled = true
    self._cRoleSkin = roleSkin
end

function LxSpineDp:GetCRoleSkin()
    if not self._cRoleSkin then
        self:InnerInitRoleSkin()
    end
    return self._cRoleSkin
end

