    self:PlayAni(animation,isLoop,ignoreTimeScale)
end

function LxSpineDp:PlayAnimationInfoEx(ani, loop, ignoreTimeScale,mixTime,timeScale,aniCompleteFunc)
    if timeScale then
        self:SetAnimationTimeScale(timeScale)
    end
    if aniCompleteFunc then
        self:SetAnimationCompleteFunc(aniCompleteFunc)
    end
    self:PlayAni(ani,loop,ignoreTimeScale,mixTime)
end

function LxSpineDp:PlayAni(animation,isLoop,ignoreTimeScale,mixTime)
    if not self._skeletonAnimation then return end

    if isLoop == nil then isLoop = true end
    ignoreTimeScale = ignoreTimeScale or false
    mixTime = mixTime or 0
    self:ClearAnimation(0)
    self:PlayAnimation(0,animation,isLoop,ignoreTimeScale,mixTime)
    self._skeletonAnimation:Update(0)
end

--- 由 LxModelDp 转换成 LxSpineDp 函数
