    self:PlayAnimationInfo(aniName,isLoop,ignoreTimeScale,callback)
end

function LxSpineDp:ClearAnimation(tranckIndex)
    if not self:IsDpValid() then return end
    self._animationState:SetEmptyAnimation(tranckIndex,0)
end

function LxSpineDp:PlayAnimation(trackIndex, ani, loop, ignoreTimeScale,mixTime)
    if not self:IsDpValid() then return false end
    if not self._skeletonAnimation then return end

    mixTime = mixTime or -1
    ignoreTimeScale = ignoreTimeScale or false
    loop = loop or false and true

    local animationState = self._animationState
    local animation = self._skeletonAnimation
    if not self._skeletonData:FindAnimation(ani) then
        if LOG_INFO_ENABLED then
            printInfo("LxSpineDp",">> not exit ani:" .. ani)
        end
        if self._isDefaultShadow then
            ani = "skill1"
        else
            animationState:ClearTrack(trackIndex)
            return false
        end
    end

    self._curAnimationName = ani

    self._bIgnoreTimeScale = ignoreTimeScale
    animation.UnscaledTime = ignoreTimeScale and true or false

    self._curTrackEntry = animationState:SetAnimation(trackIndex, ani, loop)

    if mixTime >= 0 then
        self._curTrackEntry.MixDuration = mixTime
    end

    return true
end

