------- AnimationComplete start
function LxSpineDp:RegisterAnimationComplete()
    self:UnRegisterAnimationComplete()

    local animationState = self._animationState
    if not animationState or not IsValid(animationState) then return end

    local func = function(transEntry)
        self:InternalAnimationCompleteEvent(transEntry)
    end
    self._completeEventFunc = func

    animationState.Complete = animationState.Complete + func
end


function LxSpineDp:UnRegisterAnimationComplete()
    local animationState = self._animationState
    if animationState and IsValid(animationState) then
        local oldFunc = self._completeEventFunc
        if oldFunc ~= nil then
            animationState.Complete = animationState.Complete - oldFunc
        end
    end
    self._completeEventFunc = nil
end

function LxSpineDp:InternalAnimationCompleteEvent(transEntry)
    local nowTrackEntry = self._curTrackEntry
    if not nowTrackEntry or not nowTrackEntry.Animation then return end

    local nowName = nowTrackEntry.Animation.Name
    if nowName == transEntry.Animation.Name then
        self:OnAniamationComplete(nowName)
    end
end

function LxSpineDp:SetAnimationCompleteFunc(func)
    self._animationCompleteFunc = func
end

---动画播放完成回调
function LxSpineDp:OnAniamationComplete(animateName)
    local func = self._animationCompleteFunc
    self._animationCompleteFunc = nil
    if func ~= nil then
        func(animateName)
    end
end
------- AnimationComplete end

