function LxSpineDp:ResumeAnimation()
    if not self:IsDpValid() then return end

    self._pause = false
    self:SetAnimationTimeScale(self._animationTimeScale or 1)
end

function LxSpineDp:SetAnimationTimeScale(timeScale)
    if self._animationTimeScale == timeScale then return end
    timeScale = timeScale or 1
    self._animationTimeScale = timeScale
    if not self._pause then
        if self._skeletonAnimation then
            self._skeletonAnimation.timeScale = timeScale
        end
    end
end

function LxSpineDp:GetSkeletonAnimation()
    return self._skeletonAnimation
end

