function LxSpineDp:MatchRectTransform()
    if self._spineType == LxSpineDp.TYPE_UI then
        if self._skeletonAnimation then
            self._skeletonAnimation:MatchRectTransformWithBounds()
        end
    end
end

function LxSpineDp:SetUISpineGray(bGray)
    if self._bUIGray == bGray then return end
    self._bUIGray = bGray
    if self._spineType ~= LxSpineDp.TYPE_UI then return end
    if not self._skeletonAnimation then return end

    --- 后续补上
    if bGray then
        self._skeletonAnimation.material = LxResUtil.GetSpineGrayMaterial()
    else
        self._skeletonAnimation.material = LxResUtil.GetSpineDefaultMaterial()
    end
end

function LxSpineDp:EnableSkeleton(bEnable)
    if self._skeletonAnimation then
        self._skeletonAnimation.enabled = bEnable
    end
end

function LxSpineDp:UpdateAllSkinParts()
    self._dirtyRecordMap[_DirtyNames.SkinDirty] = false

    local cRoleSkin = self:GetCRoleSkin()
    for k,v in pairs(self._skinParts) do
        local partName = v:GetPartName()
        local asset = v:GetAsset()
        if asset ~= nil then
            cRoleSkin:SetPart(partName, asset, "default", false)
        end
    end
    if cRoleSkin.isDirty then
        cRoleSkin:ApplySkin()
    end
end

function LxSpineDp:OnSkinPartLoaded(skinPart)
    if self:IsNullDp() then
        self._dirtyRecordMap[_DirtyNames.SkinDirty] = true
        return
    end
    local cRoleSkin = self:GetCRoleSkin()
    local asset = skinPart:GetAsset()
    local partName = skinPart:GetPartName()
    if asset ~= nil then
        cRoleSkin:SetPart(partName, asset, "default", false)
    else
        cRoleSkin:ClearPart(partName)
    end
    if cRoleSkin.isDirty then
        cRoleSkin:ApplySkin()
    end
end

function LxSpineDp:SetSkinPart(partName, skinName)
    local part = self._skinParts[partName]
    if not part then
        part = require("LApp.component.dp.LxSkinPart"):New(partName)
        self._skinParts[partName] = part
        part:SetLoadedCallback(self.OnSkinPartLoaded, self)
    end
    if(part:GetSkinName() == skinName) then return end
    part:SetSkin(skinName)
end

function LxSpineDp:ClearSkinPart(partName)
    local part = self._skinParts[partName]
    if part then
        self._skinParts[partName] = nil
        part:Dispose()
        local cRoleSkin = self:GetCRoleSkin()
        cRoleSkin:ClearPart(partName)
        if cRoleSkin.isDirty then
            cRoleSkin:ApplySkin()
        end
    end
end

