--- 回收对象
function LxSpineDp:Recycle(time)
    LxBaseDp.Recycle(self, time)
    self._animationCompleteFunc = nil

    local dirtyRecordMap = self._dirtyRecordMap
    for k,v in pairs(dirtyRecordMap) do
        dirtyRecordMap[v] = false
    end

    self:EnableSkeleton(false)
end

function LxSpineDp:PopRecycle()
    LxBaseDp.PopRecycle(self)

    self:EnableSkeleton(true)
end

--- 获取当前播放 Spine 的动画名字
function LxSpineDp:GetCurAniName()
    return self._curAnimationName
end
