    [_DirtyNames.Scale] = LxSpineDp.UpdateScale,
    [_DirtyNames.LocalEulerAngles] = LxSpineDp.UpdateEulerAngles,
    [_DirtyNames.Alpha] = LxSpineDp.UpdateAlpha,
    [_DirtyNames.Visible] = LxSpineDp.UpdateVisible,

    [_DirtyNames.Flip] = LxSpineDp.UpdateFlip,
    [_DirtyNames.RendererLayerName] = LxSpineDp.UpdateRenderLayer,
    [_DirtyNames.RendererOrder] = LxSpineDp.UpdateRenderOrder,

    [_DirtyNames.SkinDirty] = LxSpineDp.UpdateAllSkinParts,

}

